// Hot-path hash:
inline uint64_t Mix64(uint64_t z) {
    z = (z ^ (z >> kMix64Shift1)) * 0xbf58476d1ce4e5b9ULL;
    z = (z ^ (z >> kMix64Shift2)) * 0x94d049bb133111ebULL;
    z = z ^ (z >> kMix64Shift3);
    return z;
}

