    if (key == AccessRecorderKey::DS_ETCD_UNKNOWN) { shouldRecord_=false; isRecord_=true; }
    else {
        shouldRecord_ = LogSampler::Instance().ShouldRecordAccess(key);
        if (shouldRecord_) { handleName_=g_keyNames[...]; beg_=clock::now(); }
        else { isRecord_=true; } // skip all subsequent work
