// log_sampler_test.cpp — random distribution check (LS-015)
TEST_F(LogSamplerTest, RandomBucketDistribution) {
    constexpr int kNumBuckets = 20;
    constexpr int kNumKeys = 100000;
    for (int i = 0; i < kNumKeys; ++i) {
        uint64_t traceHash = static_cast<uint64_t>(i * 997);
        int bucket = i % kNumBuckets;
        if (s.ShouldSampleEvent(traceHash, DIAGNOSTIC, halfRate))
            bucketHits[bucket]++;
    }
    for (int b = 0; b < kNumBuckets; ++b)
        EXPECT_NEAR(ratio[b], 0.5, 0.05);  // 50%±5% per bucket
}
// log_sampler_integration_test.cpp — diagnostic supplement
TEST_F(LogSamplerIntegrationTest, DiagnosticSupplementSampling) {
    ASSERT_TRUE(LogSampler::Instance().UpdateConfigFromFlags(MakeConfig(0.0, 0.5, 0.0)));
    // request sampled out, diagnostic rate=0.5 → ~50% ERROR events
    for (int i = 0; i < 10000; ++i) LOG(ERROR) << ...;
    EXPECT_NEAR(ratio, 0.5, 0.05);
}
